import React, { useEffect, useState } from 'react';
import api from '../api';

const DoctorList = () => {
  const [doctors, setDoctors] = useState<any[]>([]);
  const [fName, setFName] = useState('');
  const [lName, setLName] = useState('');
  const [spec, setSpec] = useState('');

  const fetchDoctors = () => {
    api.get('doctors/').then((res: any) => setDoctors(res.data));
  };

  useEffect(() => { fetchDoctors(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      // KINI ANG SAKTONG FIELDS BASE SA IMONG MODELS.PY
      await api.post('doctors/', { 
        first_name: fName, 
        last_name: lName, 
        specialization: spec 
      });
      setFName(''); setLName(''); setSpec('');
      fetchDoctors();
    } catch (err: any) {
      console.error("Error details:", err.response?.data);
    }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="flex gap-2 bg-blue-50 p-4 rounded-lg">
        <input className="border p-2 rounded w-full" placeholder="First Name" value={fName} onChange={e => setFName(e.target.value)} required />
        <input className="border p-2 rounded w-full" placeholder="Last Name" value={lName} onChange={e => setLName(e.target.value)} required />
        <input className="border p-2 rounded w-full" placeholder="Specialization" value={spec} onChange={e => setSpec(e.target.value)} required />
        <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">Add</button>
      </form>
      <table className="min-w-full bg-white border">
        <thead className="bg-blue-600 text-white">
          <tr><th className="p-3 text-left">Doctor Name</th><th className="p-3 text-left">Specialization</th></tr>
        </thead>
        <tbody>
          {doctors.map((d: any) => (
            <tr key={d.doctor_id} className="border-b">
              <td className="p-3">{d.first_name} {d.last_name}</td>
              <td className="p-3">{d.specialization}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DoctorList;
